parameters.jsCode:
// Cattura l'esito dell'approvazione e arricchisce il payload.
// L'output del nodo Send-and-Wait varia leggermente per versione di n8n: in
// genere espone $json.approved (boolean) o $json.data.approved. Il nodo
// gestisce entrambi i pattern.
//
// Tre esiti distinti, non due:
//   - approved === true   -> 'approvata'
//   - approved === false  -> 'rifiutata'  (click esplicito su 'Rifiuto')
//   - approved == null    -> 'timeout'    (limitWaitTime esaurito, n8n
//                                          auto-resume senza click)
// Collassare timeout in 'rifiutata' nasconderebbe casi di escalation persa,
// problema reale perche' il gate triggera proprio su urgenza critica e
// key-account.

const dati_orig = $('Agente Decisionale').first().json;
const risposta = $input.first().json;
const raw = risposta.approved ?? risposta.data?.approved;

let esito;
if (raw === true) esito = 'approvata';
else if (raw === false) esito = 'rifiutata';
else esito = 'timeout';

// Approvatore hardcoded per portabilita' del JSON. n8n blocca di default
// l'accesso a $env.* nelle espressioni (N8N_BLOCK_ENV_ACCESS_IN_NODE=true).
// Per override in deploy reali: editare questa stringa e il campo `sendTo`
// di `Email Approvazione (Send & Wait)`, oppure sbloccare l'accesso a env
// e tornare al pattern `$env.DIGITSERVE_APPROVER_EMAIL || 'operations@...'`.
const approvatore = 'operations@digitserve.it';

return [{
  json: {
    ...dati_orig,
    approvazione: {
      richiesta: true,
      esito,
      timestamp: new Date().toISOString(),
      approvatore
    }
  }
}];

// Esegui Piano - dispatcher mock per le azioni del piano.
//
// Singolo nodo invece di SplitOut + Switch + 5 executor + Uniforma + Aggregate.
// Motivazione: n8n con `executionOrder: v1` processa gli item depth-first dopo
// uno SplitOut. Un fan-out a 5 branch seguito da aggregazione produce N run
// indipendenti del downstream (uno per item) e nessun nodo a valle riesce a
// vedere l'intero array di esiti in una sola esecuzione. Il dispatcher
// concentrato qui rimuove la patologia, produce un singolo `esiti[]`
// consumabile da Costruisci Riepilogo, e mantiene lo schema esito_azione
// invariato.
//
// PASSAGGIO A PRODUZIONE: ognuno dei 5 handler diventa una chiamata HTTP
// Request verso il sistema reale (ServiceNow, Salesforce, Slack/Teams,
// sistema reportistica, queue interna del team data). Per preservare la
// visualita' del canvas in produzione e' lecito uno Switch + 5 HTTP Request
// paralleli SE il workflow finisce in un Code aggregator come questo (il
// problema cross-iteration sparisce perche' non c'e' piu' SplitOut prima).

const dati = $input.first().json;
const piano = dati.decisione?.piano || [];

const makeId = (prefix) => prefix + '-' +
  Date.now().toString(36).toUpperCase().slice(-6) + '-' +
  Math.random().toString(36).slice(2, 6).toUpperCase();

const now = () => new Date().toISOString();

// Handler per tipo. Schema esito_azione uniforme:
// tipo / target / stato / riferimento / errore / timestamp / dettaglio_mock.
const handlers = {
  ticket: (azione) => ({
    tipo: 'ticket',
    target: azione.target,
    stato: 'eseguita',
    riferimento: makeId('TKT'),
    errore: null,
    timestamp: now(),
    dettaglio_mock: {
      titolo: azione.params.titolo,
      cliente: azione.params.cliente,
      urgenza: azione.params.urgenza,
      priorita: azione['priorità']
    }
  }),
  crm: (azione) => ({
    tipo: 'crm',
    target: azione.target,
    stato: 'eseguita',
    riferimento: makeId('EVT'),
    errore: null,
    timestamp: now(),
    dettaglio_mock: {
      id_cliente: azione.params.cliente?.id_cliente || 'unknown',
      evento: azione.params.evento,
      canale_origine: azione.params.canale_origine
    }
  }),
  notifica: (azione) => ({
    tipo: 'notifica',
    target: azione.target,
    stato: 'eseguita',
    riferimento: makeId('NTF'),
    errore: null,
    timestamp: now(),
    dettaglio_mock: {
      destinatario: azione.target,
      oggetto: azione.params.oggetto
    }
  }),
  report: (azione) => ({
    tipo: 'report',
    target: azione.target,
    stato: 'eseguita',
    riferimento: makeId('RPT'),
    errore: null,
    timestamp: now(),
    dettaglio_mock: {
      cliente: azione.params.cliente,
      servizio: azione.params.servizio,
      eta_completamento_h: 24
    }
  }),
  analisi: (azione) => ({
    tipo: 'analisi',
    target: azione.target,
    stato: 'accodata',
    riferimento: makeId('ANL'),
    errore: null,
    timestamp: now(),
    dettaglio_mock: {
      coda: 'team_data',
      servizio: azione.params?.servizio,
      contesto: azione.params?.contesto
    }
  })
};

// Tipo sconosciuto: esito 'fallita' con errore esplicito, NON ticket
// silenzioso cliente-facing. Previene regressioni se un nuovo tipo entra a
// monte senza estendere il dispatcher.
const fallback = (azione) => ({
  tipo: azione.tipo || 'sconosciuto',
  target: azione.target || null,
  stato: 'fallita',
  riferimento: null,
  errore: `tipo_azione_non_supportato: ${azione.tipo}`,
  timestamp: now(),
  dettaglio_mock: null
});

const esiti = piano.map(azione => {
  const h = handlers[azione.tipo];
  return h ? h(azione) : fallback(azione);
});

return [{
  json: {
    ...dati,
    esiti
  }
}];

// Costruzione del riepilogo strutturato e dell'audit record.
// Output:
//   - audit_record: snapshot completo destinato all'archivio immutabile.
//   - risposta_sincrona: oggetto restituito al chiamante (subset utile).
//
// Due path di ingresso convergono qui:
//   1. Path 'eseguito': arriva da Esegui Piano con array `esiti` gia'
//      aggregato (un elemento per ogni azione del piano).
//   2. Path 'bloccato': arriva direttamente dal IF di rifiuto/timeout senza
//      passare dal dispatcher; non c'e' campo `esiti`.

const first = $input.first().json;
const eseguito = Array.isArray(first.esiti);
const esiti = eseguito ? first.esiti : [];
const dati_base = first;

const totali = {
  totali: esiti.length,
  eseguite: esiti.filter(e => e.stato === 'eseguita').length,
  fallite: esiti.filter(e => e.stato === 'fallita').length,
  accodate: esiti.filter(e => e.stato === 'accodata').length,
  sconosciute: esiti.filter(e => e.stato === 'sconosciuto').length
};

// Esito complessivo. Il ramo bloccato distingue tre causali differenti per
// non collassarle nell'audit (compliance: la causa del mancato esecuzione
// deve essere ricostruibile).
const esito_approvazione = dati_base.approvazione?.esito;
let esito_complessivo;
if (!eseguito) {
  if (esito_approvazione === 'rifiutata') {
    esito_complessivo = 'rifiutata';
  } else if (esito_approvazione === 'timeout') {
    esito_complessivo = 'timeout_approvazione';
  } else {
    esito_complessivo = 'nessuna_azione';
  }
} else {
  esito_complessivo = (
    totali.fallite > 0 ? 'parziale' :
    totali.totali === 0 ? 'nessuna_azione' :
    totali.accodate > 0 && totali.eseguite === 0 ? 'accodata' :
    totali.accodate > 0 ? 'completata_con_code' :
    'completata'
  );
}

// Azioni bloccate: sul ramo no-execution riportiamo il piano che NON e' stato
// eseguito, cosi' l'approvatore (o l'auditor) sa cosa era stato pianificato.
const azioni_bloccate = (!eseguito && Array.isArray(dati_base.decisione?.piano))
  ? dati_base.decisione.piano.map(p => ({ tipo: p.tipo, target: p.target, priorita: p['priorità'] }))
  : [];

const audit_record = {
  correlation_id: dati_base.correlation_id,
  ricevuta_at: dati_base.ricevuta_at,
  chiusa_at: new Date().toISOString(),
  canale: dati_base.canale,
  mittente: dati_base.mittente,
  testo_originale: dati_base.testo_originale,
  interpretazione: dati_base.interpretazione,
  interpretazione_meta: dati_base.interpretazione_meta,
  decisione: dati_base.decisione,
  approvazione: dati_base.approvazione,
  esiti,
  azioni_bloccate,
  totali,
  esito_complessivo
};

const messaggi = {
  completata: 'Tutte le azioni richieste sono state completate con successo.',
  completata_con_code: 'Azioni sincrone completate; alcune azioni sono state messe in coda per esecuzione asincrona.',
  accodata: 'Nessuna esecuzione sincrona; tutte le azioni sono state messe in coda.',
  parziale: 'Alcune azioni sono fallite. Verificare il dettaglio nei log.',
  rifiutata: `Richiesta rifiutata dall'approvatore. ${azioni_bloccate.length} azione/i pianificata/e non sono state eseguite.`,
  timeout_approvazione: `Approvazione non pervenuta entro il timeout. ${azioni_bloccate.length} azione/i in attesa.`,
  nessuna_azione: 'Nessuna azione e\' stata eseguita.'
};

const risposta_sincrona = {
  correlation_id: audit_record.correlation_id,
  esito: esito_complessivo,
  totali,
  azioni: esiti.map(e => ({
    tipo: e.tipo,
    stato: e.stato,
    riferimento: e.riferimento,
    errore: e.errore
  })),
  azioni_bloccate,
  approvazione: dati_base.approvazione,
  provider_llm: dati_base.interpretazione_meta?.provider_usato,
  messaggio: messaggi[esito_complessivo] || messaggi.nessuna_azione
};

return [{ json: { audit_record, risposta_sincrona } }];

// Persisti Audit Log  (simulazione interna)
//
// Simula la scrittura del record di audit su un archivio append-only.
//
// PASSAGGIO A PRODUZIONE: sostituire con HTTP Request verso l'endpoint reale
// (Postgres tabella append-only, Elasticsearch index immutabile, S3 bucket con
// object lock, o data warehouse dedicato). La retention raccomandata e 24 mesi
// in linea con i requisiti tipici di compliance.

const dati = $input.first().json;
const audit_id = 'AUD-' +
  Date.now().toString(36).toUpperCase().slice(-6) + '-' +
  Math.random().toString(36).slice(2, 6).toUpperCase();

return [{
  json: {
    ...dati,
    audit_persistence: {
      audit_id,
      stato: 'persistito_mock',
      archiviato_at: new Date().toISOString()
    }
  }
}];
